python3 -c "
import json

with open('/home/user/myproject/pyramid_spec.json') as f:
    spec = json.load(f)

# Check all acceptance criteria
errors = []

# 1. Data URL
data_url = spec.get('data', {}).get('url', '')
if data_url != 'https://vega.github.io/vega-datasets/data/population.json':
    errors.append(f'Data URL mismatch: {data_url}')
else:
    print('✅ Data URL correct:', data_url)

# 2. transform_calculate
transforms = spec.get('transform', [])
calc_transforms = [t for t in transforms if 'calculate' in t]
if not calc_transforms:
    errors.append('No calculate transform found')
else:
    calc = calc_transforms[0]
    expr = calc.get('calculate', '')
    if 'datum.sex' in expr and '-datum.people' in expr:
        print('✅ transform_calculate correct:', expr)
    else:
        errors.append(f'Calculate expression incorrect: {expr}')

# 3. transform_filter
filter_transforms = [t for t in transforms if 'filter' in t]
if not filter_transforms:
    errors.append('No filter transform found')
else:
    filt = filter_transforms[0].get('filter', '')
    print('✅ transform_filter present:', filt)

# 4. Mark is bar
mark = spec.get('mark', {})
mark_type = mark.get('type', mark) if isinstance(mark, dict) else mark
if mark_type == 'bar':
    print('✅ Mark is bar')
else:
    errors.append(f'Mark is not bar: {mark_type}')

# 5. X encoding
x_enc = spec.get('encoding', {}).get('x', {})
x_type = x_enc.get('type', '')
x_field = x_enc.get('field', '')
x_axis = x_enc.get('axis', {})
x_format = x_axis.get('format', '')
x_label_expr = x_axis.get('labelExpr', '')

if x_type == 'quantitative':
    print('✅ X encoding is quantitative')
else:
    errors.append(f'X encoding type is not quantitative: {x_type}')

if x_format:
    print(f'✅ X axis has format: {x_format}')
else:
    errors.append('X axis missing format')

if 'abs(' in x_label_expr:
    print(f'✅ X axis labelExpr references abs(: {x_label_expr}')
else:
    errors.append(f'X axis labelExpr missing abs(: {x_label_expr}')

# 6. Y encoding
y_enc = spec.get('encoding', {}).get('y', {})
y_type = y_enc.get('type', '')
y_field = y_enc.get('field', '')
y_sort = y_enc.get('sort', '')

if y_type == 'ordinal':
    print('✅ Y encoding is ordinal')
else:
    errors.append(f'Y encoding type is not ordinal: {y_type}')

if y_field == 'age':
    print('✅ Y field is age')
else:
    errors.append(f'Y field is not age: {y_field}')

if y_sort == 'descending':
    print('✅ Y sort is descending')
else:
    errors.append(f'Y sort is not descending: {y_sort}')

# 7. Color encoding
color_enc = spec.get('encoding', {}).get('color', {})
color_type = color_enc.get('type', '')
color_scale = color_enc.get('scale', {})
color_legend = color_enc.get('legend', {})

if color_type == 'nominal':
    print('✅ Color encoding is nominal')
else:
    errors.append(f'Color encoding type is not nominal: {color_type}')

domain = color_scale.get('domain', [])
range_ = color_scale.get('range', [])
if domain == [1, 2]:
    print(f'✅ Color scale domain: {domain}')
else:
    errors.append(f'Color scale domain incorrect: {domain}')

if len(range_) == 2:
    print(f'✅ Color scale range: {range_}')
else:
    errors.append(f'Color scale range incorrect: {range_}')

label_expr = color_legend.get('labelExpr', '')
if 'Male' in label_expr and 'Female' in label_expr:
    print(f'✅ Color legend labelExpr: {label_expr}')
else:
    errors.append(f'Color legend labelExpr incorrect: {label_expr}')

# 8. Parameter
params = spec.get('params', [])
if len(params) == 1:
    param = params[0]
    bind = param.get('bind', {})
    if bind.get('input') == 'select':
        print('✅ Parameter has binding_select')
    else:
        errors.append(f'Parameter bind input is not select: {bind}')

    options = bind.get('options', [])
    if 1980 in options:
        print('✅ Options include 1980')
    else:
        errors.append(f'Options do not include 1980: {options}')

    value = param.get('value', None)
    if value == 1980:
        print('✅ Parameter initial value is 1980')
    else:
        errors.append(f'Parameter initial value is not 1980: {value}')
else:
    errors.append(f'Expected exactly 1 parameter, found {len(params)}')

print()
if errors:
    print('❌ ERRORS:')
    for e in errors:
        print(f'  - {e}')
else:
    print('🎉 All acceptance criteria passed!')
"
